var tasker_User_Form_Preferences = Class.create();
tasker_User_Form_Preferences.prototype = {
    initialize: function() {
		this.g_taskUserFormPreferences = {};
		var sessionPreferences = gs.getSession().getClientData('DTech_FormPreferences');
		if (sessionPreferences) {
			this.g_taskUserFormPreferences = JSON.parse(sessionPreferences);
			return this.g_taskUserFormPreferences;
		} else {
			if(typeof this.g_taskUserFormPreferences != undefined){
				if (typeof this.g_taskUserFormPreferences.lastRefreshDateTime != undefined){
					var lastRefreshDateTime = this.g_taskUserFormPreferences.lastRefreshDateTime;
					var lastUpdatedDateTime = this._getLastUpdated();
					if(lastUpdatedDateTime != undefined && lastRefreshDateTime >= lastUpdatedDateTime){
						// if records exist and the last time preferences were loaded is later than the last update, then return.
						// no need to reload the preferences as they haven't changed
						return;
					}
				}
			}
			// set the global object
			this.g_taskUserFormPreferences = this._loadFormPreferences();
			gs.getSession().putClientData('DTech_FormPreferences', JSON.stringify(this.g_taskUserFormPreferences));
			return this.g_taskUserFormPreferences;
		}
    },

	// Get last updated time
	_getLastUpdated: function(){
		var gr_user_preferences = new GlideRecord('x_153465_discovert_task_form_preferences');
		gr_user_preferences.addQuery('u_active', true);
		// put the highest order first as they take precedence
		gr_user_preferences.orderByDesc('sys_updated_on');
		gr_user_preferences.query();
		// move to first record and return the time
		if(gr_user_preferences.next()){
			var lastUpdated = new GlideDateTime(gr_user_preferences.getValue('sys_updated_on')).getNumericValue();
			return lastUpdated;
		} else {
			// no records to load return undefined
			return undefined;
		}
	},

	_loadFormPreferences: function (){
		var taskUserFormPreferences = {};
		taskUserFormPreferences.Preferences = [];
		// TODO - Load the list of Form preferences for the user, OU and Top OU
		var gr_user_preferences = new GlideRecord('x_153465_discovert_task_form_preferences');
		gr_user_preferences.addQuery('u_active', true);
		// put the highest order first as they take precedence
		gr_user_preferences.orderByDesc('u_order');
		gr_user_preferences.query();
		var fields = gr_user_preferences.getElements();

		while(gr_user_preferences.next()){
			var userPrefernce = {};
			for (var i = 0; i < fields.length; i++) {
				var glideElement = fields[i];
				var key = glideElement.getName();
				if(!key.startsWith('sys_')){
					userPrefernce[key] = {};
					// set the display value the same way reguardless of field
					userPrefernce[key].displayValue = gr_user_preferences.getDisplayValue(glideElement.getName());

					switch (key){
						case 'u_related_table_view':
							// lookup the view (used in URL)
							userPrefernce[key].value = gr_user_preferences.getElement('u_related_table_view').getRefRecord('sys_ui_form').getElement('view').getRefRecord('sys_ui_view').getValue('name');
							break;
						case 'u_related_table':
							// lookup the table name (used in URL)
							userPrefernce[key].value = gr_user_preferences.getValue(glideElement.getName());
							break;
						case 'u_service_portal':
							// lookup the service portal url_suffix (used in URL)
							userPrefernce[key].value = gr_user_preferences.getElement('u_service_portal').getRefRecord('sp_portal').getValue('url_suffix');
							break;
						case 'u_servicenow_form_view':
							// lookup the service from view (used in URL)
							userPrefernce[key].value = 
								gr_user_preferences.getElement('u_servicenow_form_view').getRefRecord('sys_ui_form').getElement('view').getRefRecord('sys_ui_view').getValue('name');
							break;
						case 'u_servicenow_portal_page':
							// lookup the page id (used in URL)
							userPrefernce[key].value = 
								gr_user_preferences.getElement('u_servicenow_portal_page').getRefRecord('sp_page').getValue('id');
							break;
						default:
							userPrefernce[key].value = gr_user_preferences.getValue(glideElement.getName());							
							break;
					}
				}
			}
			taskUserFormPreferences.Preferences.push(userPrefernce);
		}	
		taskUserFormPreferences.lastRefreshDateTime =  new GlideDateTime().getNumericValue();

		// STRY0113838
		taskUserFormPreferences.defaultServicePortal = this._getDefaultServicePortalSuffix();
		return taskUserFormPreferences;
	},

	_getDefaultServicePortalSuffix: function(){
		var gr_sp_portal = new GlideRecord('sp_portal');
		gr_sp_portal.addQuery('default', 'true');
		gr_sp_portal.addQuery('sys_scope', 'c6b1162d4fc10300303dc3818110c7b1');

		gr_sp_portal.query();
		if (gr_sp_portal.next()) {
			return gr_sp_portal.getValue('url_suffix');
		}		
	},

	loadMyFormPreferences: function (OUsWhereIamAMember, OUsWhereIamATaskManager){
		var userID = gs.getUserID();

		// if user's OUs are not passed in, load them
		// USE this for all loadMy - because it uses session variable to avoid loading
		if(!OUsWhereIamAMember)
			OUsWhereIamAMember = new x_153465_discovert.tasking_System_Settings_Scripts().getOUsWhereIamAMember();

		if (!OUsWhereIamATaskManager) {
			OUsWhereIamATaskManager = new x_153465_discovert.tasking_System_Settings_Scripts().getMyOUTaskManagers();
		}

		// DFCT0010708
		return this._userFormPreferences(userID, OUsWhereIamAMember, OUsWhereIamATaskManager);		
	},

	// DFCT0010708
	loadUserFormPreferences: function (userID){
		var tsss = new x_153465_discovert.tasking_System_Settings_Scripts();
		var OUsWhereUserIsAMember = tsss.getOUsWhereUserIsAMember(userID);
		var OUsWhereUserIsTaskManager = tsss.getUserOUTaskManagers(userID);

		return this._userFormPreferences(userID, OUsWhereUserIsAMember, OUsWhereUserIsTaskManager);
	},

	// DFCT0010708
	_userFormPreferences: function (userID, OUsWhereUserIsAMember, OUsWhereUserIsTaskManager){
		var userInfo = new x_153465_discovert.UserInfoScripts();
		var isAdministrator = userInfo.UserHasRoleScoped('x_153465_discovert.tasker_global_Tasking_Authority_member_admin', userID);
		var isTaskExecutive = userInfo.UserHasRoleScoped('x_153465_discovert.Task_Executive', userID);
		var isTaskManager = (OUsWhereUserIsTaskManager.length > 0);

		// TODO - need to define function for get my top OUs in order to use this field - u_user_in_top_ou
		// TODO - ADD TASK CHECKS for Hierarchy
		// load global preferences, things that apply to all users
		var userPreferences = this.g_taskUserFormPreferences.Preferences.filter(function (pref){
			var matchFailure = 
				(pref.u_task_user.displayValue != '' && pref.u_task_user.displayValue != null && pref.u_task_user.value != userID) || 
				((pref.u_user_in_ou.displayValue != '' && pref.u_user_in_ou.displayValue != null)  && (OUsWhereUserIsAMember.indexOf(pref.u_user_in_ou.value)<0)) ||
				(pref.u_user_in_role.value == 'task_manager' && isTaskManager != true)  ||
				(pref.u_user_in_role.value == 'task_administrator' && isAdministrator != true) ||
				(pref.u_user_in_role.value == 'task_executive' && isTaskExecutive != true);
			if(!matchFailure){
				return pref;
			}
		});
		return userPreferences;
	},

	// DFCT0010708
	get_URL_Properties_for_Task_and_User_Based_on_Prefrences: function (userID, sys_id, current_view){
		// set defaults
		var url_Properties = {};
		url_Properties.pageId = 'discovertasker_taskdetails';
		url_Properties.pageTable = 'x_153465_discovert_route_task_instance';
		url_Properties.view = current_view;
		url_Properties.portal_url_ref = this.g_taskUserFormPreferences.defaultServicePortal;
		var gr_task_pref = new GlideRecord(url_Properties.pageTable);
		if(gr_task_pref.get(sys_id)){
			var getFormToLoadOptions = this.g_taskUserFormPreferences.Preferences.filter(function (pref){
				var matchFailure = 
					(pref.u_task_user.displayValue != '' && pref.u_task_user.displayValue != null && pref.u_task_user.value.toString().indexOf(userID)==-1) || 
					(pref.u_task_category.displayValue != '' && pref.u_task_category.displayValue != null  && pref.u_task_category.value.toString().indexOf(gr_task_pref.getValue('category'))==-1) ||
					(pref.u_tasker_sub_category.displayValue != '' && pref.u_tasker_sub_category.displayValue != null  && pref.u_tasker_sub_category.value.toString().indexOf(gr_task_pref.getValue('sub_category'))==-1) || 
					(pref.u_task_state.displayValue != '' && pref.u_task_state.displayValue != null  && pref.u_task_state.displayValue.toString().indexOf(gr_task_pref.getDisplayValue('state'))==-1) ||
					(pref.u_task_task_type.displayValue != '' && pref.u_task_task_type.displayValue != null  && pref.u_task_task_type.value.toString().indexOf(gr_task_pref.getValue('tasker_type'))==-1);
				if(!matchFailure){
					return pref;
				}
			});

			// If a match was found for this task, then use first item as 
			// form preferences were loaded in order by the ORDER 
			// to override the default settings
			if(getFormToLoadOptions.length > 0){
				var formToLoad = getFormToLoadOptions[0];
				if(formToLoad.u_servicenow_portal_page.displayValue != '' && formToLoad.u_servicenow_portal_page.displayValue != null){
					url_Properties.pageId = formToLoad.u_servicenow_portal_page.value;	
				}
				if(formToLoad.u_servicenow_form_view.displayValue != '' && formToLoad.u_servicenow_form_view.displayValue != null){
					url_Properties.view = formToLoad.u_servicenow_form_view.value;	
				}
				if(formToLoad.u_service_portal.displayValue != '' && formToLoad.u_service_portal.displayValue != null){
					url_Properties.portal_url_ref = '../' + formToLoad.u_service_portal.value;	
				}
			}				
		}
		return url_Properties;
	},

	// DFCT0010708
	get_URL_Properties_for_Task_Based_on_Prefrences: function(sys_id, current_view){
		var currentUserId = gs.getUserID();
		return this.get_URL_Properties_for_Task_and_User_Based_on_Prefrences (currentUserId, sys_id, current_view);
	},


	// DFCT0010708
	getEmailLink: function(currentTask){
		//create a task link using form preferences and the current sys_id
		var task_url = this.getEmailUrl(currentTask);

		// TODO, NEED TO TAKE STYLING OUT OF HERE!
		var task_link = "<span style='font-family: georgia, palatino; font-size: 12pt;'><a href='" + task_url + "'>" + 
			currentTask.number + " - " + currentTask.task_name +
			"</a></span>";
		return task_link;

	},
	// DFCT0010708
	getEmailUrl: function(currentTask){
		// check for assigned member
		var userID = currentTask.getValue('assigned_to') + '';
		if(userID == ''){
			// check for Task Onwer
			userID = currentTask.getValue('u_task_requester') + '';
		}
		if(userID == ''){
			// use originator
			userID = currentTask.getValue('originator') + '';
		}
		var userPreferences =  this.loadUserFormPreferences(userID);
		var url_Properties = this.get_URL_Properties_for_Task_and_User_Based_on_Prefrences(userID, currentTask.getUniqueValue(),'sp');

		var pageId = url_Properties.pageId && url_Properties.pageId != '' ? url_Properties.pageId : 'discovertasker_taskdetails';
		var view = url_Properties.view && url_Properties.view != '' ? url_Properties.view : 'sp';

		//create a task link using form preferences and the current sys_id
		return task_url = url_Properties.portal_url_ref + '?sys_id='+ currentTask.sys_id +'&view=' + view + '&id=' + pageId + '&table=x_153465_discovert_route_task_instance';

	},

    type: 'tasker_User_Form_Preferences'
};
